#include <pthread.h>
#include <stdio.h>
#include <errno.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>

#include "disco.h"

enum {
  SEX_DAMA = 0,
  SEX_VARON = 1,
  SEX_COUNT = 2
};

static pthread_mutex_t disco_mutex;
static pthread_cond_t disco_cond;
static unsigned long next_ticket[SEX_COUNT];
static unsigned long serving_ticket[SEX_COUNT];
static unsigned long waiting_count[SEX_COUNT];
static size_t capacity[SEX_COUNT];
static char **waiting_name[SEX_COUNT];
static char **partner_name[SEX_COUNT];

static void die(const char *msg) {
  perror(msg);
  exit(1);
}

static void ensure_capacity(int sex, unsigned long ticket) {
  size_t needed = (size_t)ticket + 1;
  if (needed <= capacity[sex])
    return;

  size_t oldcap = capacity[sex];
  size_t newcap = oldcap == 0 ? 64 : oldcap;
  while (newcap < needed)
    newcap *= 2;

  char **new_waiting = realloc(waiting_name[sex], newcap * sizeof(*new_waiting));
  if (new_waiting == NULL)
    die("realloc");
  char **new_partner = realloc(partner_name[sex], newcap * sizeof(*new_partner));
  if (new_partner == NULL)
    die("realloc");

  for (size_t i = oldcap; i < newcap; i++) {
    new_waiting[i] = NULL;
    new_partner[i] = NULL;
  }

  waiting_name[sex] = new_waiting;
  partner_name[sex] = new_partner;
  capacity[sex] = newcap;
}

static char *dance(int sex, char *nom) {
  int other = 1 - sex;
  char *res;

  if (pthread_mutex_lock(&disco_mutex) != 0)
    die("pthread_mutex_lock");

  unsigned long my_ticket = next_ticket[sex]++;
  ensure_capacity(sex, my_ticket);
  waiting_name[sex][my_ticket] = nom;
  partner_name[sex][my_ticket] = NULL;

  if (waiting_count[other] > 0) {
    unsigned long other_ticket = serving_ticket[other];
    ensure_capacity(other, other_ticket);

    partner_name[other][other_ticket] = nom;
    partner_name[sex][my_ticket] = waiting_name[other][other_ticket];
    waiting_count[other]--;
    serving_ticket[other]++;

    if (pthread_cond_broadcast(&disco_cond) != 0)
      die("pthread_cond_broadcast");

    res = partner_name[sex][my_ticket];
    waiting_name[sex][my_ticket] = NULL;
    partner_name[sex][my_ticket] = NULL;

    if (pthread_mutex_unlock(&disco_mutex) != 0)
      die("pthread_mutex_unlock");
    return res;
  }

  waiting_count[sex]++;
  while (partner_name[sex][my_ticket] == NULL) {
    if (pthread_cond_wait(&disco_cond, &disco_mutex) != 0)
      die("pthread_cond_wait");
  }

  res = partner_name[sex][my_ticket];
  waiting_name[sex][my_ticket] = NULL;
  partner_name[sex][my_ticket] = NULL;

  if (pthread_mutex_unlock(&disco_mutex) != 0)
    die("pthread_mutex_unlock");
  return res;
}

void discoInit(void) {
  memset(next_ticket, 0, sizeof(next_ticket));
  memset(serving_ticket, 0, sizeof(serving_ticket));
  memset(waiting_count, 0, sizeof(waiting_count));
  memset(capacity, 0, sizeof(capacity));
  memset(waiting_name, 0, sizeof(waiting_name));
  memset(partner_name, 0, sizeof(partner_name));

  if (pthread_mutex_init(&disco_mutex, NULL) != 0)
    die("pthread_mutex_init");
  if (pthread_cond_init(&disco_cond, NULL) != 0)
    die("pthread_cond_init");
}

void discoDestroy(void) {
  if (pthread_cond_destroy(&disco_cond) != 0)
    die("pthread_cond_destroy");
  if (pthread_mutex_destroy(&disco_mutex) != 0)
    die("pthread_mutex_destroy");

  for (int sex = 0; sex < SEX_COUNT; sex++) {
    free(waiting_name[sex]);
    free(partner_name[sex]);
    waiting_name[sex] = NULL;
    partner_name[sex] = NULL;
    capacity[sex] = 0;
  }
}

char *dama(char *nom) {
  return dance(SEX_DAMA, nom);
}

char *varon(char *nom) {
  return dance(SEX_VARON, nom);
}

