const fs = require('fs');

const files = ['resultados.txt', 'disco.c'];
const table = new Uint32Array(256);
for (let n = 0; n < 256; n++) {
  let c = n;
  for (let k = 0; k < 8; k++) {
    c = (c & 1) ? (0xEDB88320 ^ (c >>> 1)) : (c >>> 1);
  }
  table[n] = c >>> 0;
}

function crc32(buf) {
  let c = 0xFFFFFFFF;
  for (const byte of buf) {
    c = table[(c ^ byte) & 0xFF] ^ (c >>> 8);
  }
  return (~c) >>> 0;
}

function u16(n) {
  const b = Buffer.alloc(2);
  b.writeUInt16LE(n >>> 0, 0);
  return b;
}

function u32(n) {
  const b = Buffer.alloc(4);
  b.writeUInt32LE(n >>> 0, 0);
  return b;
}

